def mask_email(email):
    parts = email.split('@')
    if len(parts) == 2:
        local_part, domain = parts
        masked_local_part = '*' * (len(local_part) - 1) + local_part[-1]
        return f"{masked_local_part}@{domain}"
    return email

def mask_phone_number(phone_number):
    length = len(phone_number)
    if length == 10:
        return phone_number[0:2] + '*' * 4 + phone_number[6:]
    return phone_number

def mask_address(address):
    parts = address.split(' ')
    if len(parts) > 3:
        street, city, state, zip_code = parts[:4]
        return f"{street} {city}, {state} {zip_code}"
    return address